import{_ as t,j as n,o as a,v as e}from"./chunks/framework.dn0DPyqd.js";const s=JSON.parse('{"title":"Ý nghĩa của các HTTP Status Code","description":"Về lựa chọn RESTful API hay gRPC chúng ta sẽ cần xem xét từng trường hợp cụ thể. Nó giống như là một chai nước tăng lực `monster` và một chai nước suối `lavie`. Mỗi chai nước sẽ phù hợp với một trường hợp cụ thể.","frontmatter":{"footer":true,"title":"Ý nghĩa của các HTTP Status Code","description":"Về lựa chọn RESTful API hay gRPC chúng ta sẽ cần xem xét từng trường hợp cụ thể. Nó giống như là một chai nước tăng lực `monster` và một chai nước suối `lavie`. Mỗi chai nước sẽ phù hợp với một trường hợp cụ thể.","authors":["lethanh"],"date":"2024-12-05T00:00:00.000Z","outline":"deep","draft":true},"headers":[{"level":2,"title":"HTTP Status code là gì ?","slug":"http-status-code-la-gi","link":"#http-status-code-la-gi","children":[]},{"level":2,"title":"HTTP Status Code 1xx: Informational","slug":"http-status-code-1xx-informational","link":"#http-status-code-1xx-informational","children":[{"level":3,"title":"100 Continue","slug":"_100-continue","link":"#_100-continue","children":[]},{"level":3,"title":"101 Switching Protocols","slug":"_101-switching-protocols","link":"#_101-switching-protocols","children":[{"level":4,"title":"Sử dụng tls để Switching Protocols khi ACK https","slug":"su-dung-tls-đe-switching-protocols-khi-ack-https","link":"#su-dung-tls-đe-switching-protocols-khi-ack-https","children":[]}]},{"level":3,"title":"102 Processing","slug":"_102-processing","link":"#_102-processing","children":[]},{"level":3,"title":"103 Early Hints","slug":"_103-early-hints","link":"#_103-early-hints","children":[]}]},{"level":2,"title":"HTTP Status Code 2xx: Success","slug":"http-status-code-2xx-success","link":"#http-status-code-2xx-success","children":[{"level":3,"title":"200 OK","slug":"_200-ok","link":"#_200-ok","children":[]},{"level":3,"title":"201 Created","slug":"_201-created","link":"#_201-created","children":[]},{"level":3,"title":"202 Accepted","slug":"_202-accepted","link":"#_202-accepted","children":[]},{"level":3,"title":"203 Non-Authoritative Information","slug":"_203-non-authoritative-information","link":"#_203-non-authoritative-information","children":[]},{"level":3,"title":"204 No Content","slug":"_204-no-content","link":"#_204-no-content","children":[]},{"level":3,"title":"205 Reset Content","slug":"_205-reset-content","link":"#_205-reset-content","children":[]},{"level":3,"title":"206 Partial Content","slug":"_206-partial-content","link":"#_206-partial-content","children":[]},{"level":3,"title":"207 Multi-Status","slug":"_207-multi-status","link":"#_207-multi-status","children":[]}]},{"level":2,"title":"HTTP Status Code 3xx: Redirection","slug":"http-status-code-3xx-redirection","link":"#http-status-code-3xx-redirection","children":[{"level":3,"title":"300 Multiple Choices","slug":"_300-multiple-choices","link":"#_300-multiple-choices","children":[]},{"level":3,"title":"301 Moved Permanently","slug":"_301-moved-permanently","link":"#_301-moved-permanently","children":[]}]}],"relativePath":"blog/2024-12-05-y-nghia-cua-cac-http-status-code.md","filePath":"blog/2024-12-05-y-nghia-cua-cac-http-status-code.md","lastUpdated":1733383193000}'),i={name:"blog/2024-12-05-y-nghia-cua-cac-http-status-code.md"},c=[e('<p>Ngày nay, mỗi một giây trôi qua, có hàng triệu request HTTP được gửi đi và nhận về trên mạng global hoặc mạng internal. HTTP là một phần không thể thiếu trong cuộc sống của chúng ta. Tuy nhiên, chỉ các lập trình viên chúng ta mới quan tâm đến các HTTP Status Code.</p><p>Một vấn đề thực tế ở Việt Nam là các lập trình thường chỉ biết đến các Status Code là <code>200</code>, <code>400</code>, <code>401</code>, <code>403</code> và <code>500</code>. Nhiều status khác như <code>201</code>, <code>204</code>, <code>206</code>, <code>301</code>... thì ít khi được sử dụng nên không được biết đến. Một vấn đề nữa là hiện tại nhiều kiểu thiết kế Wapper Response được sử dụng nên khi trả về lỗi hay thành công đôi khi vẫn là 200 hoặc chỉ có 200 và 400.</p><p>Bài viết này mình sẽ chia sẻ với các bạn về ý nghĩa của các HTTP Status Code thông dụng và cách sử dụng chúng.</p><h2 id="http-status-code-la-gi" tabindex="-1">HTTP Status code là gì ? <a class="header-anchor" href="#http-status-code-la-gi" aria-label="Permalink to &quot;HTTP Status code là gì ?&quot;">​</a></h2><p>Theo tài liệu rfc của HTTP thì <a href="https://www.rfc-editor.org/rfc/rfc2616.html#page-39" target="_blank" rel="noreferrer">HTTP code</a> là một số nguyên không âm gồm 3 chữ số, mỗi một số đại diện cho một ý nghĩa cụ thể.</p><p>HTTP Status Code được sử dụng để thông báo nhanh cho client về kết quả của request mà nó đã gửi đi. Client sẽ có cái nhìn tổng quan nhanh về kết quả của request chứ chưa cần kiểm tra kỹ content response, ví dụ thành công hay thất bại.</p><h2 id="http-status-code-1xx-informational" tabindex="-1">HTTP Status Code 1xx: Informational <a class="header-anchor" href="#http-status-code-1xx-informational" aria-label="Permalink to &quot;HTTP Status Code 1xx: Informational&quot;">​</a></h2><p>1xx là nhóm status code dùng để thông báo cho client rằng request của nó đã được nhận và xử lý. Client không cần phải làm gì cả.</p><h3 id="_100-continue" tabindex="-1">100 Continue <a class="header-anchor" href="#_100-continue" aria-label="Permalink to &quot;100 Continue&quot;">​</a></h3><p>HTTP này thông báo rằng client đã gửi request phần đầu tiên(Header) và server đã chấp nhận request và sẵn sàng body để xử lý dữ liệu, thường điều này xảy ra khi body rất lớn và client có thể gửi phần tiếp theo(Body).</p><p>Ví dụ: Request từ client:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>POST /upload HTTP/1.1</span></span>\n<span class="line"><span>Host: example.com</span></span>\n<span class="line"><span>Content-Type: application/json</span></span>\n<span class="line"><span>Content-Length: 1024</span></span>\n<span class="line"><span>Expect: 100-continue</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Trong trường hợp này:</p><p>Client đang thông báo rằng yêu cầu của nó có một body với kích thước (1024 bytes) và mong đợi phản hồi 100 Continue từ máy chủ trước khi gửi phần thân dữ liệu.</p><p>Server sẽ response :</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>HTTP/1.1 100 Continue</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Sau đó, client gửi body của yêu cầu, ví dụ:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>{</span></span>\n<span class="line"><span>  &quot;fileName&quot;: &quot;example.txt&quot;,</span></span>\n<span class="line"><span>  &quot;fileContent&quot;: &quot;Base64 encoded content here...&quot;</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Kết quả cuối cùng:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>HTTP/1.1 201 Created</span></span>\n<span class="line"><span>Content-Type: application/json</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>{</span></span>\n<span class="line"><span>  &quot;status&quot;: &quot;success&quot;,</span></span>\n<span class="line"><span>  &quot;fileId&quot;: &quot;12345&quot;</span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/XP91IyD048Nl-ok6FPkqgTL33r8CWe9e8JtcicucpU9sDcGdfIB-TtSthIA8dXBsxSpxtalMdjN0uzuAmOOjmlrsku5YFeVI4HiQ4JAe67juUKjF8VemOBJf5J78qXeabg0yb3-L2eS33acfX2WXku5g1PldQWkpiRTEDSbhLkH5JVVEymhmgFQznLoxVKrtnnvrE0micJwnr1IfWc7sYBJZBggBfI3728FPTGokZIwJDmoeqHpGGuUgmS7NfAW1tQ5-zN1GrZI6tuIe80jmvUgBvqV-QRl5DYqFjwR8tykzsP6oDR43Zs4_Tm46VReUtnl5whk0TzaQYqzgZt85yfoOZomlQahQAMAKRvN7woKWQTTW89-KFC_bn_-Xsz7QP3x5JX_QGpyuZTuRslqMV34le1nGCJOrlSimmwEF97xKSKnUG69yQE9XiRXSNfrH_cWejj2QK5BifNVaKOXrg2hyTfy0" alt="uml diagram"></div><h3 id="_101-switching-protocols" tabindex="-1">101 Switching Protocols <a class="header-anchor" href="#_101-switching-protocols" aria-label="Permalink to &quot;101 Switching Protocols&quot;">​</a></h3><p>Hiện tại HTTP/2 và HTTP/3 đã rất phổ biến và được sử dụng. Tuy nhiên không phải server nào cũng hỗ trợ HTTP/2 hoặc HTTP/3.</p><p>Vì vậy mặc định client sẽ request đến server là HTTP/1.1, nếu server hỗ trợ HTTP/2 hoặc HTTP/3 thì server sẽ trả về status code 101 Switching Protocols để thông báo cho client chuyển sang giao thức mới.</p><p>Sau đó client sẽ gửi lại request theo giao thức mới.</p><p>Thực tế, status code này ít được sử dụng bởi các lập trình viên bình thường, thường các framework sẽ tự động xử lý.(Được handler bởi người viết framework, lib)</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/dPBBJiCm44Nt_eeXQv8I2YooG4KHeXARIYcmoSPr9ebLnmxszCNNuoPjKv00YQtdSS-zuuaZRcdLA4QI5C9qFfz1V1L3jf4aQgahc5b3HXZb88GtN6H6B97WfQqiBv2nrizB8Lkk2O9KITGK07UGVgraQDTekqh6M0hXFMG9F3tEOIHgJftmA8xYN4-DemHmovjMOIHCa-k3M08RNBXEFzUfqHe5IQEJ8qokCnJXYJ5ynbq2V27Ywt4KHT-hhsXTDnsFcJQ4O6LL4vXo3zRZWaM1SeqEgFPrV5-X8o03gwCWrmM86iNIGOt-nJh6CWYzkpGvUVefq7yRUn02Mn_ITlTnStldlVK659OTlvVk3p7m2wDBQHk-NxjlQGyCu3giuIB3XHjqZbUUBPYYKkRoaCb5y7TQmvA24-zJikXQemi7QydF6euWPx7zWj3RyWWJr8N_jPy0" alt="uml diagram"></div><p>Thực tế, status code này ít được sử dụng.</p><h4 id="su-dung-tls-đe-switching-protocols-khi-ack-https" tabindex="-1">Sử dụng tls để Switching Protocols khi ACK https <a class="header-anchor" href="#su-dung-tls-đe-switching-protocols-khi-ack-https" aria-label="Permalink to &quot;Sử dụng tls để Switching Protocols khi ACK https&quot;">​</a></h4><p>Có 1 cách nữa mà đa số được sử dụng là tại thời điểm bắt tay tls handshake, client sẽ gửi lên danh sách protocol mà nó hỗ trợ, server sẽ chọn ra protocol phù hợp và trả về cho client.</p><h3 id="_102-processing" tabindex="-1">102 Processing <a class="header-anchor" href="#_102-processing" aria-label="Permalink to &quot;102 Processing&quot;">​</a></h3><p>Status code này thông báo rằng server đang xử lý request nhưng chưa hoàn thành. Client có thể chờ đợi hoặc gửi request khác.</p><p>Thực tế, status code này ít được sử dụng.</p><h3 id="_103-early-hints" tabindex="-1">103 Early Hints <a class="header-anchor" href="#_103-early-hints" aria-label="Permalink to &quot;103 Early Hints&quot;">​</a></h3><p>Status code này được sử dụng để thông báo cho client rằng client cần tài trước một số thông tin trước khi nhận response chính thức.</p><p>Ví dụ: Để hiển thị một HTMl thì client cần tải trước một số file css, js, image... để hiển thị đúng.</p><p>Thực tế, status code này ít được sử dụng.</p><h2 id="http-status-code-2xx-success" tabindex="-1">HTTP Status Code 2xx: Success <a class="header-anchor" href="#http-status-code-2xx-success" aria-label="Permalink to &quot;HTTP Status Code 2xx: Success&quot;">​</a></h2><p>HTTP Status Code 2xx là nhóm status code thông báo cho client rằng request của client đã được xử lý thành công.</p><h3 id="_200-ok" tabindex="-1">200 OK <a class="header-anchor" href="#_200-ok" aria-label="Permalink to &quot;200 OK&quot;">​</a></h3><p>Status code này thông báo rằng request của client đã được xử lý thành công và thông tin được trả về trong response( Nếu có ).</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/LP31JiCm44Jl_efHxccRSii1LOfGAu448ZdcOhdRniXT6tjJG8X_nsrAWVFCphpPLH8TPJmu9LOSOTDrJrWk5dYyHubsD8PIseqEp_GwKXAbGlPROuDcGT4uIom5T4BpNsaf7YcUbLQf1kKjsXhhkmxpICcFqKnbysfMzRpnIMhGkpu4HpFZ3ugz4ABT3mA_EvrEWGZHdv0eGOPi-A5gKUQ6fhvcNaRqt7YMp5Xs7u5gw12SDLgiv_bBylohFn3lPQXHBM_GCpwBhHPTr2WkLCNNnEHeTqRANTFw36787gz4ANXErFERbU4l96rnYbGhucr--3S0" alt="uml diagram"></div><h3 id="_201-created" tabindex="-1">201 Created <a class="header-anchor" href="#_201-created" aria-label="Permalink to &quot;201 Created&quot;">​</a></h3><p>Status code này thông báo rằng request của client đã được xử lý thành công và một resource mới đã được tạo ra. Thường được sử dụng khi client gửi request POST để tạo mới một resource.</p><p>Response sẽ chứa thông tin về resource mới được tạo ra.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/ZT6nJiCm40RWtKznyamQKc39W2fbwO2W8XcpMCwL63bdOrzQ4EBTSPAsmCPgo___-MuJMGKU1oi46xO8swRPmVgwW2gWOkmWWsUCRWmQpqT2-FJ6QECLCSZA6YIMe29KVszg30SCyqqjH0NPFTGbx9xg1d8zPyrrUR4gMjgwo2NWkngynPLsGqkL8qxHMVFXiGJblJLQiN6KlqP7BNrAKWFA4kGZ7YzC-IN8fUXWNde6jvyw5mduu3J6Y16uHvW9AGq2leqOMOWQicIioWlhzoHQUd1BVGbvE9NbnVhczku_r3He7kE4ZQEU5F8AfEdImHnnGblSp-PaMEQQS1hDuKHEjTvHn9QEXlkVNwGzdKNG8IjZen0Rf2vjzXi0" alt="uml diagram"></div><h3 id="_202-accepted" tabindex="-1">202 Accepted <a class="header-anchor" href="#_202-accepted" aria-label="Permalink to &quot;202 Accepted&quot;">​</a></h3><p>Status code này thông báo rằng request của client đã được chấp nhận và sẽ được xử lý sau. Thường được sử dụng khi client gửi request để xử lý một công việc nào đó mà không cần phải trả về kết quả ngay lập tức.</p><p>Ví dụ: Gửi email, chạy job build, xử lý dữ liệu lớn...</p><p>Mục đích của status code này là để thông báo cho client rằng request của nó đã được chấp nhận và sẽ được xử lý sau bởi một worker khác.</p><p>Response sẽ không chứa thông tin về kết quả của request nhưng có thể sẽ chứa thông tin về job worker sẽ xử lý request.</p><p>Ví dụ bạn gửi request để xử lý một công việc nào đó, server sẽ trả về 202 Accepted và thông tin về id của task sẽ xử lý công việc đó.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/dPDFJm8n4CNl_HIJFGieYV_sO30ReyO3nEMubzeTeB9CQpjBDCRlRjj553L6FRRJplkzD-t8itJShXeXM7E3S3MTJc2uFuHpfT0orj23MtneqVFxrimuc3YZq7jDSo5iwA6Ljf8OigBHI9o1z53iLafqQtIfKWfHGEyCoXmcut8A0zkrI_g3W_v1HLV6SmxuA5UsmRuogueAGnnwzwPF5dEGrZPQITQ61lVUK4NF6Kk_pF8eHJNWIkecUn5a6C7f-OB1pA9a1m8E5UerUk15g7ScAvBXfanEFMXENkq7hoNq0dUHRqbtqleDOuYSMnyfvUPMjWU9_BeEkwSdnqU76-W6Puavo7MnVcRsrf37YZJLIORc7yt08aHzXqWWjtpHpwpbrk6EhRTfN5w4ONI4WqJoqqI-9hkXL990BL0j4qtNBfw8gsWK6idelWzp7yOtVujHKxGo3sduVoKPWJQChQq3cH2Zy7x2htW5" alt="uml diagram"></div><h3 id="_203-non-authoritative-information" tabindex="-1">203 Non-Authoritative Information <a class="header-anchor" href="#_203-non-authoritative-information" aria-label="Permalink to &quot;203 Non-Authoritative Information&quot;">​</a></h3><p>HTTP Status code này thông báo rằng request đã được xử lý thành công nhưng thông tin trả về không phải từ server gốc mà từ một server khác.</p><p>Các ứng dụng sử dụng các dịch vụ proxy hoặc cache có thể sử dụng mã 203 để chỉ ra rằng thông tin trả về không phải từ nguồn gốc mà từ một nguồn khác.</p><p>Thực tế, status code này ít được sử dụng.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/dP9FJuH03CNlyoaQxkowUkDWrX3Z6XEN18vS9aDt6OKEpdJ_nVZTBU2gU35w8oslxzStNGRMddTjenHRRX1MHP71vSKLF3gARtPSEszPizqZtDF6-LQ-7IdLYSmQssbYYDB68d44Ea0wxMJU7Kz38visSlHxz4CdLog5-1go1Evk2vXNclN0CL_C5YMjNE04yAZRhi6PSQqYnmZURci6j-bbWmkO6irp0Bi1or3BOAEbL44_JwcijyZ_Po6oaHSwxmo6W06ubX_mPOU1GLC50QaQgwDV3l6uqzb6Khs0zKD9gIEMkEBYr642kkiQQuPKvq_1KKclKJyXIY1Q2u4btGmZexUHgi7DTE_0pdy0kRD02fsZWCFUmf5EE7vvtRyWfbyP_mGKp_4mXCQWU7o-o9ckf8Fb6ZGSj2TBsrv5GgOdPFRxtIqbPZdNTm00" alt="uml diagram"></div><h3 id="_204-no-content" tabindex="-1">204 No Content <a class="header-anchor" href="#_204-no-content" aria-label="Permalink to &quot;204 No Content&quot;">​</a></h3><p>HTTP Status code này thông báo rằng request đã được xử lý thành công nhưng không có thông tin(Body) nào được trả về.</p><p>Tuy nhiên, đầu ra của phản hồi vẫn có thể chứa các thông tin hữu ích trong phần header, ví dụ như thông tin về các tài nguyên tiếp theo có thể được yêu cầu hoặc hướng dẫn về hành động tiếp theo.</p><p>Ví dụ với method <code>put</code> hoặc <code>delete</code> client chỉ cần biết là đã thành công.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/NP2zRiCm38HtFSKXSvqqHISFHG37G8QYA6gFMGoPYGd8eYlHQH-_YbMaFol9k-zukwXTq7bqnYYh8npQzXKFzuzu4LJYbRoYG3DRIp6UPeStUfyfAZvOXrz7nap9Y2rFNLAiAiTfk48NKVtTD1Gk59PDOqo5uWbDYNtzNBSrDe6YpC7c79ljUdlq1ubQWZwxSNAqjZ8QBqe8V1uKShggioUc8DUK5A53ElWEgeAU72L9dcQ0CGsAnAxA6-hVsndZwBHGqbt-AJbOuiiD4YVnaOv-wSCBR5RVWNtFjbFsPyIV-fOeBDwO7Va-5Vy5" alt="uml diagram"></div><h3 id="_205-reset-content" tabindex="-1">205 Reset Content <a class="header-anchor" href="#_205-reset-content" aria-label="Permalink to &quot;205 Reset Content&quot;">​</a></h3><p>HTTP Status code này thông báo rằng client cần reset lại form mà nó đã gửi đi. Thường được sử dụng trong trường hợp client gửi form và server xử lý thành công và cần client reset lại form submit.</p><p>Thực tế, status code này ít được sử dụng.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/PP4_JyCm4CLtVufJPjm_I2mPKALqw4P48gOinhbIIuvjVEUc2F7TSTmAWHZltjExdvztn2focgmGRDWY7Fg-XVlD0pmZ8KFZ7QDZa7b-JqWCRVGQYN2ykrdsNgTfyRmOd8K8ESze4rJUL8qrMQb04JH_bGxZ6MDHEY4Qa8_GrT0-TJsiARrEXkNHnwdmhBUhxU0EdhW6lAWfM5nfFmtkHYVxZu0rg12iqOgDT-kBdEUv9CWKBJhjHnm7zrajgxrYLTLG9S88neN4rPTmdX6YUJin-EF2SYM4S7il0PyG2bFX8yftXEX0PlIc_W7zNzurskAn96VhjHM8gD6SSt142juH3awvSPcGVrtp4SwbsHswCV_KDm00" alt="uml diagram"></div><h3 id="_206-partial-content" tabindex="-1">206 Partial Content <a class="header-anchor" href="#_206-partial-content" aria-label="Permalink to &quot;206 Partial Content&quot;">​</a></h3><p>HTTP Status code này thông báo rằng server đã trả về một phần dữ liệu của resource mà client yêu cầu. Thường được sử dụng khi client yêu cầu một phần dữ liệu của file lớn.</p><p>HTTP code này được sử dụng rất nhiều trong quá khứ, hiện tại 2024 thì nó đã giảm bớt.</p><p>Trong quá khứ, khi client yêu cầu một file lớn, server sẽ trả về dữ liệu theo từng phần, client sẽ nhận từng phần và hiển thị dữ liệu.</p><p>Ví dụ: Khi xem video trên mạng, client sẽ yêu cầu từng phần dữ liệu của video và hiển thị chứ không cần tải toàn bộ video lên đến vài GB về.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/hPC_Ry8m4CLtVueJ4mmcWQAsYjGAAQhAY4X65ZTSm99Zk_PHmRUldKGf_ICnqCswktVlvsTvwKauEZQACPAa45PbkOPvUW_hK9T2GMuqeIRWGsM3tXhjaJ4RAvMq8lH7kP9XRWJ2G_wzKw3xGDTs2iPouCzGPF3wKa9IozupcKrdMxqodZB0asYimcbbcgtU2Bt73DxEXFufvRDqViUq8GGdzmS2KyTTdJSuV3-Y9my2N9J5RYk4SGfa88edK3lJ01qGeZbZ1V00b6S3nb_Nt-h-m2zveED9vkdYyMkYFDim8AnLiX8aZKvCHKZSaqFHTF0AwvOzs7RfW4UzyorMVmlSWUqXgluDnfUkazkY32iMF80_N4ypGcayqQzGuuwOQrmpkIt90UUVmsovOuvn81P-P3du1lvbK8Mly0a0" alt="uml diagram"></div><p>Thực tế bây giờ kỹ thuật HLS, Dash đã phổ biến nên status code này ít được sử dụng.</p><h3 id="_207-multi-status" tabindex="-1">207 Multi-Status <a class="header-anchor" href="#_207-multi-status" aria-label="Permalink to &quot;207 Multi-Status&quot;">​</a></h3><p>HTTP Status code này thông báo rằng request của client đã được xử lý thành công nhưng response chứa nhiều thông tin về trạng thái của các tài nguyên khác nhau.</p><p>Status này được sử dụng khi request của người dùng yêu cầu xử lý nhiều tài nguyên cùng một lúc và mỗi tài nguyên có một trạng thái khác nhau.</p><p>Ví dụ: Client gửi request để xóa nhiều file, server sẽ trả về 207 Multi-Status và thông tin về trạng thái của từng file.</p><p>Thực tế, status code này ít được sử dụng.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/XL9DImCn4BtdLmnxKkZsYuAm1ocibAhObcvlheUmdRQHtKbCPaKf_UzcDzsAA7WAcJVptfkNJ1rBotLL2i6AIuJvPhE2yV06dkgILPonvDf17Ax6DvmhgTwY0qMm98GrEgF98LmzPCl5jH36awf26KaCKLeg98v0-gcVI8Rs7MsBP4Aa4Dz2bi1glLpDxXTtC2XqMMB1IbFhQp3gZtAQQyS9u8Uil9r-eIj1cX6isXyOzAvX28fWyQr6nmwCrGQzhdVi6wfk5OjErxO8UqZuLXCYWzYRIPEBxgzCSaeriPU9Dvy64v36bAgGpVZWrMdAwPWJGDIgXP4eWUUc1d0CXuSF5dU-7WqwCwEeTm5TDnQDXqDOFaO1EVN-PHd_oJ8PJc2X6MQwfcr7rXmlEPr2Z2NksXJzwk5rV4fSMt8-e7QLED0ruRLldbFXSv2A5EtXZEsq1PJ5uP9m4t3pDHgaaYp456dhVzqN" alt="uml diagram"></div><h2 id="http-status-code-3xx-redirection" tabindex="-1">HTTP Status Code 3xx: Redirection <a class="header-anchor" href="#http-status-code-3xx-redirection" aria-label="Permalink to &quot;HTTP Status Code 3xx: Redirection&quot;">​</a></h2><p>Hiểu đơn giản HTTP Status Code 3xx là nhóm status code thông báo cho client rằng client cần thực hiện một hành động khác để hoàn thành request.</p><h3 id="_300-multiple-choices" tabindex="-1">300 Multiple Choices <a class="header-anchor" href="#_300-multiple-choices" aria-label="Permalink to &quot;300 Multiple Choices&quot;">​</a></h3><p>HTTP Status code này thông báo rằng request của client có nhiều lựa chọn để chọn. Client cần chọn một trong số các lựa chọn được trả về. Ví dụ: Client request một resource mà có nhiều phiên bản, client cần chọn một phiên bản để xem.</p><p>Thực tế, status code này ít được sử dụng.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/dLF1Jjmm4BtxAvvyPbbeRpaWgeWMgQgAoDv83yOxkt7b7RksGuiG_yuaORUmG8LwzCoyUM_UIqvpCQdq6wzKSSKJpXUB2tmyEiAttXSNfL9tmLdAcFqjNL9Cb8cBAIvmngSRuxovzgHKb7NEkcYuGDVUoP26oQYVTnfADvJ6JgDKZTa9cWfVpXQOo-RG9pj9cHyV7hTy7dAfG7_CHjWFRTWe3eMGtBeh2Ai1Eb4XqQ-USiamsEqfdIdeX6cprHz3paxaoiopGvHgC1CfTRKZVzMBbkl0HM2pnMsa2YP6x-ouO_up1sxvhcL0ssbSLxWQti2TxfENfzvTEIVM1z3UyBetQnfwPxpsBdVw_k1Dq2hjWpudOljFZEZOmpIInKWqO7wqV3_PwcarkYekJ34DLiR0oupVhdHYhSWR9ymsTpnUYbL8uZVjp7yZMxdwl-BDvCbAke5fQ0nCBpIy5k872V7xrtV4fkqqyIG7R4llj6SGDUcavTu71iTutAhKAV5IVhm7" alt="uml diagram"></div><h3 id="_301-moved-permanently" tabindex="-1">301 Moved Permanently <a class="header-anchor" href="#_301-moved-permanently" aria-label="Permalink to &quot;301 Moved Permanently&quot;">​</a></h3><p>HTTP Status code này thông báo rằng request của client đã được chuyển hướng vĩnh viễn đến một URL khác. Hiện tại HTTP Status code này vẫn được sử dụng rất nhiều, nó thường phục vụ cho việc một URL bị thay đổi hoặc một trang web bị chuyển địa chỉ.</p>',88)];const l=t(i,[["render",function(t,e,s,i,l,h){return a(),n("div",null,c)}]]);export{s as __pageData,l as default};
